update public.lessons l set enhancements = $ench${"industryStory":"Asked \"how would you test a login page?\", one candidate listed random clicks; another structured it — positive, negative, boundary, security — and sounded like a professional. Same feature, very different impression, decided by structure.","davidTip":"For any \"how would you test X?\" question, answer with a structure: positive, negative, boundary, and a non-functional angle (security/performance/usability). Structure signals competence even before the specific cases.","miniChallenge":"Answer \"how would you test a text search box?\" out loud in under 60 seconds, using a clear structure.","modelAnswer":"## Example\n\"Positive: a term with matches returns results. Negative: no-match shows a friendly message; empty term is handled. Boundary: very long query, special characters. Non-functional: results return within ~2s, and it's keyboard accessible.\"","resourcePreview":{"name":"QA Interview Question Bank","purpose":"Common QA questions with concise model answers.","whenToUse":"Use it to rehearse fundamentals in your own words.","formats":["PDF","DOCX"]}}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'qa-interview-accelerator'
  and m.module_number = 3 and l.lesson_number = 1;

update public.lessons l set enhancements = $ench${"industryStory":"\"What's the difference between severity and priority?\" trips up a surprising number of candidates. The ones who nail it define both in a line and give a quick example — instantly sounding clear and experienced.","badGood":{"label":"answering \"severity vs priority\"","bad":"\"They're kind of the same... severity is how bad it is and priority is also how bad it is.\"","good":"\"Severity is the technical impact; priority is the business urgency. A homepage logo typo is low severity but high priority — it's cosmetic, but everyone sees it.\""},"davidTip":"For any \"difference between\" question, define both terms in one line each, then give one example. That tiny structure makes you sound confident and clear — and it works for most fundamentals questions.","miniChallenge":"Write one-line-each-plus-example answers for: severity vs priority, verification vs validation, smoke vs regression.","modelAnswer":"## Example\nVerification vs validation: \"Verification is 'are we building it right?' (reviews); validation is 'are we building the right thing?' (testing against user needs) — e.g. a feature can pass review yet fail to meet what users actually need.\"","resourcePreview":{"name":"Defect Severity vs Priority Guide","purpose":"A clear reference for classifying defects and answering this classic question.","whenToUse":"Revise from it before the technical round.","formats":["PDF","DOCX"]}}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'qa-interview-accelerator'
  and m.module_number = 3 and l.lesson_number = 2;

update public.lessons l set enhancements = $ench${"industryStory":"A candidate confidently said \"regression and retesting are the same thing\" — and lost credibility. The test-type questions are easy marks if you know them, and easy ways to stumble if you do not.","visualAid":{"type":"comparison","title":"Test types you must be able to define","headers":["Type","One-line answer"],"rows":[["Retesting","Re-test the specific fixed defect"],["Regression","Check nothing else broke after a change"],["Smoke","Quick check the build is stable enough to test"],["Sanity","Narrow check of a specific area after a change"]]},"davidTip":"Retesting vs regression is the classic trap: retesting confirms a specific fix; regression confirms the change broke nothing else. Knowing these crisply is low-effort, high-return interview prep.","miniChallenge":"Define retesting, regression, smoke and sanity in one line each, then give an example that uses two of them together.","modelAnswer":"## Example\n\"After a payment fix, I retest the specific bug to confirm it's resolved, then run regression on checkout and related areas to confirm the fix didn't break anything else.\""}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'qa-interview-accelerator'
  and m.module_number = 3 and l.lesson_number = 3;

update public.lessons l set enhancements = $ench${"davidTip":"For this assignment, answer in your own words with an example each — memorised definitions sound hollow. The goal is to explain the idea clearly, the way you would to an interviewer.","miniChallenge":"Before submitting, say each answer out loud as if to an interviewer; tighten any that ramble past ~30 seconds.","managersReview":{"intro":"If I ran your technical round, I would look for:","strengths":["Crisp definitions in your own words","An example with each answer","Structured \"how would you test X\" answers"],"gaps":["Confusing severity/priority or regression/retest","Definitions with no example","Rambling, unstructured answers"],"improvements":["Define-in-a-line + example","Structure test-design answers","Practise out loud for concision"]},"portfolioBuilder":"Pair fundamentals with proof: when you explain test design, mention your test case pack; when you discuss defects, mention your bug report. Theory plus evidence is the winning combination."}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'qa-interview-accelerator'
  and m.module_number = 3 and l.lesson_number = 4;


