update public.lessons l set enhancements = $ench${"industryStory":"\"A critical bug reaches production — what do you do?\" One candidate panicked and rambled; another calmly walked through assess → contain → communicate → fix → learn. The structured answer sounded like someone you would actually want on the team.","visualAid":{"type":"flow","title":"Structuring a scenario answer","steps":[{"label":"Clarify","detail":"ask any needed context"},{"label":"Approach","detail":"how you would think about it"},{"label":"Actions","detail":"concrete steps"},{"label":"Outcome","detail":"communicate + learn"}]},"davidTip":"Scenario questions test your thinking, not a \"correct\" answer. Clarify first, then talk through a structured approach. As an interviewer, I am listening for calm, logical reasoning — not a memorised script.","miniChallenge":"Answer \"you find a serious bug an hour before release\" using clarify → approach → actions → outcome.","modelAnswer":"## Example\n\"First I'd clarify the impact and how many users it affects. I'd reproduce and document it clearly, then communicate the risk to the team and PO with options: fix now, hotfix, or ship with the issue documented. The decision is the business's; my job is to inform it clearly and fast.\"","resourcePreview":{"name":"QA Interview Question Bank","purpose":"Includes scenario questions with model approaches.","whenToUse":"Rehearse scenario answers from it.","formats":["PDF","DOCX"]}}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'qa-interview-accelerator'
  and m.module_number = 5 and l.lesson_number = 1;

update public.lessons l set enhancements = $ench${"industryStory":"\"A bug you missed reached production — tell me about it.\" A candidate who said \"that never happens to me\" lost credibility instantly. The one who owned a real example and what they changed afterwards came across as honest and growth-minded.","davidTip":"Never claim you have never missed a bug — it sounds dishonest. Own a real example, explain what you learned and changed (a new check, better data), and you demonstrate exactly the maturity interviewers want.","miniChallenge":"Draft a STAR answer for \"a defect that reached production\" that ends on what you learned and improved.","modelAnswer":"## Example\nS: a discount edge case slipped to production. T: I needed to handle it and prevent a repeat. A: I reproduced it, raised a clear bug, and added boundary cases for discount logic to our regression set. R: it was fixed quickly and we never saw that class of bug again."}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'qa-interview-accelerator'
  and m.module_number = 5 and l.lesson_number = 2;

update public.lessons l set enhancements = $ench${"industryStory":"\"The requirements are unclear and the deadline is tight — what do you do?\" The weak answer was \"I just test as much as I can\". The strong answer showed prioritising by risk and communicating trade-offs — exactly how real testers cope under pressure.","davidTip":"Under unclear requirements or tight deadlines, show risk-based prioritisation and communication: clarify what you can, test the highest-risk areas first, and make the residual risk explicit. \"I'd test the critical paths and flag what I couldn't cover\" is the mature answer.","miniChallenge":"Answer \"tight deadline, unclear requirements, can't test everything\" — show how you prioritise and what you communicate.","modelAnswer":"## Example\n\"I'd quickly clarify the most important user journeys with the PO, focus my testing on those highest-risk paths, and timebox the rest. I'd then report clearly what I covered, what I didn't, and the residual risk — so the release decision is informed.\"","portfolioBuilder":"Scenario answers are stronger with evidence. If your portfolio shows risk-based test planning or an RTM, mention it — it proves you really do prioritise by risk."}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'qa-interview-accelerator'
  and m.module_number = 5 and l.lesson_number = 3;

update public.lessons l set enhancements = $ench${"davidTip":"For this assignment, structure every scenario answer and stay calm and honest — especially on \"missed bug\" questions. Interviewers reward composure and ownership over a pretend-perfect record.","miniChallenge":"Before submitting, check each scenario answer follows a clear structure and ends on a constructive outcome or lesson.","managersReview":{"intro":"If I asked you scenario questions, I would look for:","strengths":["Calm, structured reasoning","Honest ownership of mistakes","Risk-based prioritisation and clear communication"],"gaps":["Panic or rambling","Claiming a perfect record","\"Test everything\" with no prioritisation"],"improvements":["Use clarify→approach→actions→outcome","Own a real example + lesson","Show how you prioritise under pressure"]}}$ench$::jsonb
