update public.lessons l set enhancements = $ench${"industryStory":"Given a live test task — \"find bugs in this page in 20 minutes\" — one candidate clicked at random; another announced their approach, applied techniques, and documented findings clearly. The structured one impressed even with fewer bugs found.","visualAid":{"type":"flow","title":"Approaching a test task","steps":[{"label":"Clarify","detail":"scope & priorities"},{"label":"Explore","detail":"understand the feature"},{"label":"Apply techniques","detail":"partitions, boundaries, negative"},{"label":"Document","detail":"clear bugs / cases"}]},"davidTip":"In a test task your *approach* is assessed as much as your findings. Narrate your thinking, apply recognisable techniques, and write up what you find clearly. A structured tester who finds five real issues beats a random clicker who finds six.","miniChallenge":"For \"test this sign-up form in 20 minutes\", write the plan you would follow before touching it.","modelAnswer":"## Example\n\"Clarify scope. Apply equivalence/boundary analysis to each field, test negative cases (empty, invalid email, weak password), check validation messages, and try one security input. Log each issue as a clear, reproducible bug and summarise coverage at the end.\"","resourcePreview":{"name":"Mock Interview Practice Pack","purpose":"Run realistic practice interviews and test tasks, with a feedback sheet.","whenToUse":"Use it to rehearse test tasks under time pressure.","formats":["PDF","DOCX"]}}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'qa-interview-accelerator'
  and m.module_number = 6 and l.lesson_number = 1;

update public.lessons l set enhancements = $ench${"industryStory":"Under a 15-minute timer, a candidate tried to write exhaustive test cases and finished almost none. Another wrote concise, prioritised cases covering the key risks and completed a coherent set. Time pressure rewards prioritisation, not perfectionism.","davidTip":"Under time pressure, prioritise: cover the critical happy path and the highest-risk negative/boundary cases first, kept concise. A complete, prioritised small set beats an unfinished exhaustive one — and shows judgement.","miniChallenge":"Give yourself 10 minutes to write prioritised test cases for a login form; note which you wrote first and why.","modelAnswer":"## Example\nFirst: valid login (critical happy path), wrong password, empty fields, account lockout after N attempts. Then, if time: email case-insensitivity, very long inputs. I lead with the highest-risk, most important behaviours."}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'qa-interview-accelerator'
  and m.module_number = 6 and l.lesson_number = 2;

update public.lessons l set enhancements = $ench${"industryStory":"In a test task, a candidate found a genuine issue but wrote \"it's broken\" with no detail — and made several silent assumptions about scope. Another raised clear, reproducible defects and stated their assumptions explicitly. The second looked instantly more professional.","badGood":{"label":"a defect in a test task","bad":"\"Login broken.\"","good":"\"Login: valid credentials show a generic error on submit. Steps: 1) enter valid email+password 2) submit. Expected: dashboard. Actual: 'Something went wrong'. Assumption: tested as a standard registered user.\""},"davidTip":"Raise defects clearly even under time pressure, and state your assumptions out loud (\"I assumed a standard user account\"). Explicit assumptions show maturity and let the interviewer follow your reasoning.","miniChallenge":"Write one clear defect from a test task and list two assumptions you would state to the interviewer.","modelAnswer":"## Example\nDefect: \"Search returns no results for valid terms with trailing spaces.\" Assumptions stated: \"I assumed search should trim whitespace, and I tested as a logged-in user on desktop Chrome.\"","portfolioBuilder":"Your bug-report and test-case artefacts are exactly what a test task asks you to produce. Practising with them means the real task feels familiar."}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'qa-interview-accelerator'
  and m.module_number = 6 and l.lesson_number = 3;

update public.lessons l set enhancements = $ench${"davidTip":"For this assignment, treat it like a real test task: structured approach, prioritised concise output, clear defects, explicit assumptions. That combination is what makes a test task a pass.","miniChallenge":"Before submitting, time-box yourself and check your output is prioritised, your defects are reproducible, and your assumptions are stated.","managersReview":{"intro":"If I marked your test task, I would look for:","strengths":["A clear, narrated approach","Prioritised, concise output","Reproducible defects with stated assumptions"],"gaps":["Random clicking","Unfinished exhaustive attempt","Vague defects, hidden assumptions"],"improvements":["Lead with an approach","Prioritise under time pressure","Write clear defects and state assumptions"]}}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'qa-interview-accelerator'
  and m.module_number = 6 and l.lesson_number = 4;


