update public.lessons l set enhancements = $ench${"industryStory":"A candidate prepared answers from scratch in every interview and kept reinventing the same stories. Another built a STAR bank — 6 reusable stories mapped to common themes — and could adapt to almost any behavioural question instantly. The bank is the difference between scrambling and flowing.","davidTip":"Prepare 5–6 strong STAR stories that each cover several themes (a defect you're proud of, a conflict, pressure, a mistake, a process improvement). Versatile stories you can adapt beat a long list of half-prepared ones.","miniChallenge":"Draft the titles of your 6 STAR stories and note which common questions each one could answer.","modelAnswer":"## Example\n1) Critical defect found late → \"proud of / under pressure\". 2) Disagreement with a dev → \"conflict / communication\". 3) Missed bug → \"mistake / learning\". 4) Improved the bug template → \"process improvement\". 5) Tight deadline → \"pressure / prioritisation\". 6) Helped a teammate → \"collaboration\".","resourcePreview":{"name":"STAR Answer Framework Workbook","purpose":"Build a bank of structured behavioural answers.","whenToUse":"Use it to draft and refine your 6 STAR stories.","formats":["DOCX","PDF"]}}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'qa-interview-accelerator'
  and m.module_number = 8 and l.lesson_number = 1;

update public.lessons l set enhancements = $ench${"industryStory":"At the end of an interview, \"any questions for us?\" — and the candidate said \"no, I think you covered everything\". It landed flat. The candidate who asked two thoughtful questions seemed genuinely interested, and it is often what interviewers remember.","davidTip":"Always prepare two thoughtful questions to ask. Good ones — about how the team approaches quality, or what success looks like in the role — signal genuine interest and turn the interview into a two-way conversation.","miniChallenge":"Write three strong questions you could ask an interviewer (about the team, quality process, or the role), and pick your top two.","modelAnswer":"## Example\n\"How does the team approach quality — is testing involved from refinement?\" \"What would success look like for this role in the first 3–6 months?\" \"What's the biggest quality challenge the team is facing right now?\""}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'qa-interview-accelerator'
  and m.module_number = 8 and l.lesson_number = 2;

update public.lessons l set enhancements = $ench${"industryStory":"Two equally-qualified candidates; one arrived calm and prepared, the other flustered by avoidable issues — untested video link, no questions ready, no copy of their CV. Preparation, not personality, is what produced the calm. The prepared one got the offer.","davidTip":"Confidence in interviews is mostly preparation, not bravado. Rehearse out loud, test your tech if remote, have your CV and portfolio to hand, and reframe nerves as energy. The calm that comes from readiness is visible — and persuasive.","miniChallenge":"Build your final interview checklist: the day before, just before, during, and the follow-up afterwards.","modelAnswer":"## Example\nDay before: re-read JD/CV, review STAR + pitch, prepare questions, test tech. Just before: quiet space, water, CV/portfolio open. During: breathe, pause before answering, use STAR, ask your questions. After: send a short thank-you and note what to improve.","resourcePreview":{"name":"Interview Confidence & Nerves Guide","purpose":"Practical techniques to stay calm and perform at your best.","whenToUse":"Use it in the days before an interview.","formats":["PDF","DOCX"]}}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'qa-interview-accelerator'
  and m.module_number = 8 and l.lesson_number = 3;

update public.lessons l set enhancements = $ench${"davidTip":"For your capstone, assemble a complete readiness pack you can actually use: your pitch, STAR bank, fundamentals notes, questions to ask, a 30-60-90 plan, and your tracked applications. This is what turns \"I'm preparing\" into \"I'm ready\".","miniChallenge":"Assemble your Interview Readiness Pack: pitch, 6 STAR stories, fundamentals cheat notes, 2 questions to ask, a 30-60-90 plan, and your application tracker.","modelAnswer":"## Example contents\n1) 60–90s pitch. 2) 6 STAR stories mapped to themes. 3) Fundamentals notes (severity/priority, test design, agile). 4) Two questions to ask. 5) A 30-60-90 day plan for a target role. 6) Application tracker with follow-up dates.","managersReview":{"intro":"If I saw your interview readiness pack as a hiring manager, I would look for:","strengths":["A versatile STAR bank","Crisp fundamentals and a clear pitch","Thoughtful questions and a 30-60-90 plan","Organised, tracked job search"],"gaps":["Stories prepared ad hoc","No questions to ask","No plan or tracking"],"improvements":["Build a reusable STAR bank","Prepare two strong questions","Add a 30-60-90 plan and a tracker"]},"portfolioBuilder":"Your readiness pack plus your QA portfolio is the complete package: proof you can do the work, and proof you can present yourself. That combination is what lands offers.","resourcePreview":{"name":"30-60-90 Day Plan Template","purpose":"Show an employer you will deliver value from day one.","whenToUse":"Include a tailored plan in your readiness pack.","formats":["DOCX","PDF"]}}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'qa-interview-accelerator'
  and m.module_number = 8 and l.lesson_number = 4;


